import React from "react";

// Lojistik iç sistemi ana sayfası — KOYU TEMA + MODERN + ANİMASYONLU İSKELET
// Ek kütüphane yok (yalnızca React). Veri yokken sayfa boş kalmasın diye
// shimmer (iskelet) ve basit animasyonlu grafik yer tutucular kullanır.
// Veri geldiğinde props ile besle; yoksa otomatik olarak iskeletler görünür.

export default function AnaSayfa({
    kpi, // { bugunTalep, bekleyenTeslimat, buAyGelir, buAyGider }
    hareketler = [], // [{tarih, tur, aciklama, tutar, durum}]
    talepler = [], // [{no, musteri, rota, kapasite, durum}]
    onYeniGelir,
    onYeniGider,
    onYeniTalep,
    onYeniTedarik,
    onTumTalepler,
}) {
    const hasKpi = Boolean(kpi);
    const hasHareket = hareketler && hareketler.length > 0;
    const hasTalep = talepler && talepler.length > 0;

    return (
        <div className="dark-root">
            <style>{`
        :root{
          --bg0:#0b0d12; --bg1:#0f1219; --panel:#111522; --muted:#97a0b8; --text:#e7ebf6; --line:#1d2433;
          --brand:#6c7cff; --brand2:#22c55e; --warn:#f59e0b; --bad:#ef4444; --ok:#16a34a;
        }
        @media (prefers-color-scheme: dark){ :root{ color-scheme:dark; } }
        .dark-root{ min-height:100dvh; color:var(--text);
          background:
            radial-gradient(90rem 50rem at 10% -10%, rgba(108,124,255,.18), transparent 60%),
            radial-gradient(70rem 40rem at 120% 0%, rgba(34,197,94,.14), transparent 60%),
            linear-gradient(180deg, var(--bg0) 0%, var(--bg1) 60%, var(--bg0) 100%);
        }
        .container{ max-width:1200px; margin:0 auto; padding:20px; }

        /* Topbar */
        .top{ position:sticky; top:0; z-index:10; backdrop-filter:saturate(1.1) blur(10px);
              border-bottom:1px solid var(--line); background:rgba(12,15,22,.6); }
        .top-in{ display:flex; align-items:center; justify-content:space-between; gap:12px; padding:10px 20px; }
        .brand{ display:flex; align-items:center; gap:10px; font-weight:800; letter-spacing:.2px; }
        .nav{ display:flex; gap:10px; }
        .nav a{ color:#c8cde0; text-decoration:none; padding:8px 10px; border-radius:10px; }
        .nav a:hover{ background:#171c2b; }

        /* Panels */
        .panel{ background:linear-gradient(180deg, #0f1422 0%, #0c1220 100%);
                border:1px solid var(--line); border-radius:16px; box-shadow:0 10px 30px rgba(0,0,0,.35); }
        .p16{ padding:16px; }

        /* Hero */
        .hero{ display:grid; grid-template-columns:1.1fr .9fr; gap:16px; margin:18px auto; }
        @media(max-width:960px){ .hero{ grid-template-columns:1fr; } }
        .title{ font-size:30px; font-weight:900; letter-spacing:-.02em; margin:0; }
        .sub{ color:var(--muted); margin:6px 0 0; }
        .actions{ display:flex; flex-wrap:wrap; gap:8px; margin-top:12px; }
        .btn{ appearance:none; border:1px solid var(--line); background:#0e1424; color:#dfe6ff;
              padding:10px 12px; border-radius:12px; font-weight:700; cursor:pointer; transition:transform .15s ease;
              box-shadow:0 8px 24px rgba(108,124,255,.12) inset, 0 4px 12px rgba(0,0,0,.25); }
        .btn.primary{ background:linear-gradient(90deg, var(--brand), #8d9bff); border-color:#2a3350; color:#0b0d12; }
        .btn:hover{ transform:translateY(-1px); }
        .btn:disabled{ opacity:.6; cursor:not-allowed; }

        /* KPIs */
        .kpis{ display:grid; grid-template-columns:repeat(4,1fr); gap:10px; margin-top:12px; }
        @media(max-width:900px){ .kpis{ grid-template-columns:repeat(2,1fr); } }
        .kpi{ background:#0e1424; border:1px solid var(--line); border-radius:12px; padding:12px; position:relative; overflow:hidden; }
        .kpi h4{ font-size:12px; color:#9aa3bf; margin:0 0 6px; font-weight:700; }
        .kpi strong{ font-size:22px; }

        /* Skeleton / shimmer */
        .shimmer{ position:relative; overflow:hidden; background:#111726; border-radius:10px; }
        .shimmer::after{ content:""; position:absolute; inset:0; transform:translateX(-100%);
          background:linear-gradient(90deg, transparent, rgba(255,255,255,.08), transparent);
          animation:sh 1.4s infinite; }
        @keyframes sh{ 100%{ transform:translateX(100%);} }

        /* Dashboard placeholder */
        .dash{ display:grid; grid-template-columns:1fr; gap:10px; }
        .bars{ display:flex; align-items:flex-end; gap:6px; height:160px; padding:10px; border:1px dashed #1f2940; border-radius:10px; }
        .bar{ width:10%; min-width:14px; background:linear-gradient(180deg, #6c7cff33, #6c7cff66); border-radius:6px; animation:grow 2.6s ease-in-out infinite; }
        .bar:nth-child(odd){ animation-delay:.4s; }
        .bar:nth-child(3n){ animation-delay:.8s; }
        @keyframes grow{ 0%,100%{ height:20%; } 50%{ height:85%; } }
        @media (prefers-reduced-motion: reduce){ .bar{ animation:none; height:50%; } .shimmer::after{ animation:none; } }

        /* Tables */
        .grid{ display:grid; grid-template-columns:1.1fr .9fr; gap:16px; margin-top:16px; }
        @media(max-width:1000px){ .grid{ grid-template-columns:1fr; } }
        .table{ width:100%; border-collapse:separate; border-spacing:0; font-size:14px; }
        .table th, .table td{ padding:10px 12px; border-bottom:1px solid var(--line); text-align:left; }
        .table thead th{ font-size:12px; color:#8d98b8; text-transform:uppercase; letter-spacing:.06em; background:#0f1628; }
        .empty{ color:#8a93ad; padding:14px; text-align:center; }

        footer{ color:#8a93ad; font-size:13px; padding:24px 20px; }
      `}</style>

            {/* TOP */}
            <div className="top">
                <div className="top-in container">
                    <div className="brand">{Logo()} Lojistik Portal</div>
                    <nav className="nav" aria-label="primary">
                        <a href="#gelirgider">Gelir‑Gider</a>
                        <a href="#talep">Talepler</a>
                        <a href="#tedarik">Tedarik</a>
                        <a href="#dashboard">Dashboard</a>
                    </nav>
                </div>
            </div>

            {/* HERO */}
            <main className="container">
                <section className="hero">
                    <div className="panel p16">
                        <h1 className="title">Operasyon Özetiniz</h1>
                        <p className="sub">Gelir‑gider, talep‑tedarik ve teslimatlar.</p>
                        <div className="actions" role="group" aria-label="Hızlı işlemler">
                            <button className="btn primary" onClick={onYeniGelir} disabled={!onYeniGelir}>Yeni Gelir</button>
                            <button className="btn" onClick={onYeniGider} disabled={!onYeniGider}>Yeni Gider</button>
                            <button className="btn" onClick={onYeniTalep} disabled={!onYeniTalep}>Talep Oluştur</button>
                            <button className="btn" onClick={onYeniTedarik} disabled={!onYeniTedarik}>Tedarik Kaydı</button>
                        </div>

                        {/* KPI alanı: veri varsa değer; yoksa shimmer */}
                        <div className="kpis" style={{ marginTop: 12 }}>
                            <div className="kpi"> <h4>Bugünkü Talepler</h4> {hasKpi ? <strong>{kpi.bugunTalep}</strong> : <div className="shimmer" style={{ height: 22 }} />} </div>
                            <div className="kpi"> <h4>Bekleyen Teslimat</h4> {hasKpi ? <strong>{kpi.bekleyenTeslimat}</strong> : <div className="shimmer" style={{ height: 22 }} />} </div>
                            <div className="kpi"> <h4>Bu Ay Gelir</h4> {hasKpi ? <strong>{formatTL(kpi.buAyGelir)}</strong> : <div className="shimmer" style={{ height: 22 }} />} </div>
                            <div className="kpi"> <h4>Bu Ay Gider</h4> {hasKpi ? <strong>{formatTL(kpi.buAyGider)}</strong> : <div className="shimmer" style={{ height: 22 }} />} </div>
                        </div>
                    </div>

                    {/* Dashboard Placeholder (animasyonlu barlar) */}
                    <div className="panel p16" id="dashboard">
                        <div className="dash">
                            <div className="bars" aria-label="Animasyonlu grafik yer tutucu">
                                {Array.from({ length: 10 }).map((_, i) => <div key={i} className="bar" />)}
                            </div>
                        </div>
                    </div>
                </section>

                {/* TABLOLAR */}
                <section className="grid">
                    <div className="panel p16" id="gelirgider">
                        <div style={{ display: "flex", alignItems: "center", justifyContent: "space-between", marginBottom: 8 }}>
                            <h3 style={{ margin: 0 }}>Son Gelir‑Gider Hareketleri</h3>
                            <div style={{ display: 'flex', gap: 8 }}>
                                <button className="btn" onClick={onYeniGelir} disabled={!onYeniGelir}>Gelir</button>
                                <button className="btn" onClick={onYeniGider} disabled={!onYeniGider}>Gider</button>
                            </div>
                        </div>
                        {hasHareket ? (
                            <table className="table">
                                <thead><tr><th>Tarih</th><th>Tür</th><th>Açıklama</th><th>Tutar</th><th>Durum</th></tr></thead>
                                <tbody>
                                    {hareketler.map((r, i) => (
                                        <tr key={i}><td>{r.tarih}</td><td>{r.tur}</td><td>{r.aciklama}</td><td>{formatTL(r.tutar)}</td><td>{r.durum}</td></tr>
                                    ))}
                                </tbody>
                            </table>
                        ) : (
                            <SkeletonTable rows={3} cols={5} />
                        )}
                    </div>

                    <div className="panel p16" id="talep">
                        <div style={{ display: "flex", alignItems: "center", justifyContent: "space-between", marginBottom: 8 }}>
                            <h3 style={{ margin: 0 }}>Aktif Talepler / Tedarik</h3>
                            <button className="btn" onClick={onTumTalepler} disabled={!onTumTalepler}>Tüm Talepler</button>
                        </div>
                        {hasTalep ? (
                            <table className="table">
                                <thead><tr><th>Talep No</th><th>Müşteri</th><th>Çıkış → Varış</th><th>Kapasite</th><th>Durum</th></tr></thead>
                                <tbody>
                                    {talepler.map((t, i) => (
                                        <tr key={i}><td>{t.no}</td><td>{t.musteri}</td><td>{t.rota}</td><td>{t.kapasite}</td><td>{t.durum}</td></tr>
                                    ))}
                                </tbody>
                            </table>
                        ) : (
                            <SkeletonTable rows={3} cols={5} />
                        )}
                    </div>
                </section>
            </main>

            <footer className="container">© {new Date().getFullYear()} Lojistik Portal</footer>
        </div>
    );
}

// ------- Yardımcılar -------
function formatTL(n) { if (n == null) return "—"; try { return n.toLocaleString('tr-TR', { style: 'currency', currency: 'TRY' }); } catch { return `${n} ₺`; } }

function SkeletonTable({ rows = 3, cols = 4 }) {
    return (
        <div>
            <div className="shimmer" style={{ height: 38, borderRadius: 10, marginBottom: 8 }} />
            <div className="shimmer" style={{ height: 38, borderRadius: 10, marginBottom: 8 }} />
            {Array.from({ length: rows }).map((_, ri) => (
                <div key={ri} style={{ display: 'grid', gridTemplateColumns: `repeat(${cols},1fr)`, gap: 8, marginBottom: 8 }}>
                    {Array.from({ length: cols }).map((_, ci) => (
                        <div key={ci} className="shimmer" style={{ height: 30, borderRadius: 8 }} />
                    ))}
                </div>
            ))}
        </div>
    );
}

// ------- Logo (SVG) -------
function Logo() {
    return (
        <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="url(#g)" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" aria-hidden>
            <defs>
                <linearGradient id="g" x1="0" y1="0" x2="1" y2="1">
                    <stop offset="0%" stopColor="var(--brand)" />
                    <stop offset="100%" stopColor="var(--brand2)" />
                </linearGradient>
            </defs>
            <rect x="3" y="3" width="18" height="18" rx="5" />
            <path d="M7 12h10M7 8h6M7 16h8" />
        </svg>
    );
}
